  "options": [
    {
      "text": "Kommt erfolgreich zum Kompilieren",
      "hint": "Können wir gleichzeitig mehrere mutable Referenzen haben?"
    },
    {
      "text": "Fehler: `wisdom` kann nicht mehr als einmal mutabel geborgt werden"
